var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님 말씀의 요지는 이해했습니다.","JPN":"シスターのお話は理解しました。","ENG":"I understand what you're saying, Sister.","TWN":"姊妹，我懂你的意思。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"성무의 집행 기간에 유예가 필요하다는 뜻이시죠?","JPN":"聖務の執行期間に猶予が必要だということですね？","ENG":"You need more time to carry out your holy mission. Is that correct?","TWN":"你是希望可以拉長執行任務的時間對吧？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아앗… 네에! 맞습니다!","JPN":"あっ……はい！　そうです！","ENG":"Ah... Yes, it is!","TWN":"喔喔…對對！沒錯！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"파견된 입장이라 당장 시국으로 돌아가는 건 어렵지만…","JPN":"派遣された立場なので、すぐに市国へ戻るのは難しいですが……","ENG":"I'm on deployment, so I can't go back to the City right now.","TWN":"因為他們派我來，但我現在無法立刻回去市局…"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"마침 이 도시에 계신 기적 심의회 자매님의 권한이라면 가능하지 않을까 해서요.","JPN":"この都市にいらっしゃる奇跡審議会のシスターの権限なら\\n可能ではないかと思いまして。","ENG":"But since you're here, I thought maybe you could use your authority as a member of the Miracle Investigation Council to help me.","TWN":"剛好奇蹟議會也在這附近，所以想說可以麻煩你嗎?"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"걱정 마세요. 자매님 사정은 신부님께 제가 잘 전해드리겠습니다.","JPN":"心配しないでください。\\nシスターの事情は神父様に私からしっかりとお伝えします。","ENG":"Sure. I'll talk to Father on your behalf. Don't worry.","TWN":"你放心，我會把你的事告訴神父的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"정말 그래 주시는 건가요?!","JPN":"本当ですか！？","ENG":"Would you really do that for me?","TWN":"真的嗎？！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"감사합니다! 이 은혜는 잊지 않겠습니다!","JPN":"ありがとうございます！　この恩恵は忘れません！","ENG":"Thank you! I won't forget this!","TWN":"謝謝你，大恩大德永生難忘！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"But?","TWN":"不過？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"성황청은 지금 얼마 전에 벌어진 다른 사건으로 다들 많이 바쁠 때라서요.","JPN":"聖皇庁は今、この前起きた他の事件でみんな忙しい時期ですので。","ENG":"The Holy Curia is completely preoccupied with a recent incident.","TWN":"聖皇廳正因為先前的事件而忙得不可開交，"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아마도 다른 파견원들의 소식에 귀 기울일 여유가 없을 것 같다는 생각이 드네요.","JPN":"おそらく他の派遣員の話に耳を傾けるような余裕はないと思います。","ENG":"I doubt anyone there will have time to listen to news about anything else.","TWN":"可能暫時沒有時間處理其他派遣人員的事務，"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그러니 자매님께선, 당장 맡고 계신 성무에만 집중해주세요.","JPN":"ですのでシスターは、今担当されている聖務だけに集中してください。","ENG":"So, for now, you should just focus on your holy mission.","TWN":"所以還是要請你先專注在交付給你的任務上。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아… 하하…","JPN":"はあ……アハハ……","ENG":"Hah... Hah hah...","TWN":"哈哈…哈…"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"결국 다시 돌아왔어요.","JPN":"結局また戻ってきてしまいました。","ENG":"So, I'm back.","TWN":"結果我又回來啦。"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"항상 곁에서 지켜주겠다고 말해 버리다니…","JPN":"いつもそばで守ってあげるなんて言ってしまうなんて……","ENG":"I can't believe I promised her that I'd protect her.","TWN":"竟然說出會一直在你身邊保護你這種話…"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저도 참 대책이 없네요.","JPN":"私ったら困ったものですね。","ENG":"I'm so irresponsible.","TWN":"應該是因為一時情急吧？"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};